blocks.body:
{
    "level": "B2–C1",
    "intro": "W tej lekcji zobaczysz, jak działają <strong>bierne formy gerunda</strong>: formy <strong>being + V3</strong> i <strong>having been + V3</strong>. Używamy ich wtedy, gdy podmiot nie wykonuje czynności sam, lecz jej podlega.",
    "rules": [
        {
            "label": "being + V3",
            "color": "emerald",
            "text": "Prosta bierna forma gerunda. Mówi o czynności równoczesnej albo ogólnej.",
            "example": "She hates being interrupted."
        },
        {
            "label": "having been + V3",
            "color": "blue",
            "text": "Forma perfect biernego gerunda. Pokazuje, że dana czynność wydarzyła się wcześniej.",
            "example": "Having been warned, he was careful."
        },
        {
            "label": "Czynnie czy biernie",
            "color": "rose",
            "text": "Porównaj: <strong>doing / having done</strong> oraz <strong>being done / having been done</strong>.",
            "example": "writing → being written → having been written"
        }
    ]
}

{
    "title": "1. Jak tworzymy bierny gerund",
    "intro": "Porównaj formy czynne i bierne:",
    "items": [
        {
            "label": "Czynny",
            "title": "doing / writing",
            "subtitle": "I enjoy writing letters. — Lubię pisać listy."
        },
        {
            "label": "Bierny",
            "title": "being done / being written",
            "subtitle": "He dislikes being criticized. — Nie lubi, gdy go krytykują."
        },
        {
            "label": "Czynny perfect",
            "title": "having done / having written",
            "subtitle": "Having finished the work, she left. — Skończywszy pracę, wyszła."
        },
        {
            "label": "Bierny perfect",
            "title": "having been done / having been written",
            "subtitle": "Having been rejected, she tried again. — Po odrzuceniu spróbowała ponownie."
        }
    ]
}

{
    "title": "2. Bierny gerund: being + V3",
    "sections": [
        {
            "label": "Po czasownikach uczuć",
            "color": "emerald",
            "description": "Bierny gerund często pojawia się po czasownikach takich jak <strong>like, hate, enjoy, love, dislike, avoid, mind</strong>.",
            "examples": [
                {
                    "en": "She hates being interrupted.",
                    "ua": "Nie znosi, kiedy ktoś jej przerywa."
                },
                {
                    "en": "Nobody likes being criticized.",
                    "ua": "Nikt nie lubi być krytykowany."
                },
                {
                    "en": "He enjoys being praised.",
                    "ua": "Lubi, kiedy jest chwalony."
                },
                {
                    "en": "I don't mind being asked questions.",
                    "ua": "Nie przeszkadza mi, kiedy ktoś zadaje mi pytania."
                }
            ]
        },
        {
            "label": "Po przyimkach",
            "color": "blue",
            "description": "Bierny gerund występuje też po przyimkach, np. <strong>without, after, before, despite, instead of</strong>.",
            "examples": [
                {
                    "en": "He left without being noticed.",
                    "ua": "Wyszedł, nie zostając zauważonym."
                },
                {
                    "en": "After being rejected, she applied again.",
                    "ua": "Po odrzuceniu złożyła wniosek ponownie."
                },
                {
                    "en": "Despite being warned, he continued.",
                    "ua": "Mimo ostrzeżenia kontynuował."
                },
                {
                    "en": "Before being hired, she had to pass a test.",
                    "ua": "Zanim ją zatrudniono, musiała zdać test."
                }
            ]
        },
        {
            "label": "Gdy podmiot jest odbiorcą działania",
            "color": "amber",
            "description": "Używamy tej formy, gdy podmiot <strong>nie wykonuje</strong> czynności, tylko jej doświadcza.",
            "examples": [
                {
                    "en": "I remember being told about it.",
                    "ua": "Pamiętam, że mi o tym powiedziano."
                },
                {
                    "en": "She denies being involved.",
                    "ua": "Zaprzecza, że była w to zamieszana."
                },
                {
                    "en": "He will never forget being helped by her.",
                    "ua": "Nigdy nie zapomni, jak mu pomogła."
                }
            ]
        }
    ]
}

{
    "title": "3. Bierny gerund perfect: having been + V3",
    "sections": [
        {
            "label": "Wcześniejsza czynność",
            "color": "emerald",
            "description": "Używamy tej formy, gdy jedna czynność wydarzyła się wcześniej i wpływa na to, co dzieje się potem:",
            "examples": [
                {
                    "en": "Having been warned, he was more careful.",
                    "ua": "Po ostrzeżeniu był ostrożniejszy."
                },
                {
                    "en": "Having been told the truth, she felt relieved.",
                    "ua": "Gdy powiedziano jej prawdę, poczuła ulgę."
                },
                {
                    "en": "Having been rejected twice, he gave up.",
                    "ua": "Po dwóch odmowach się poddał."
                }
            ]
        },
        {
            "label": "Styl formalny",
            "color": "blue",
            "description": "Ta forma jest częsta w stylu formalnym, akademickim i oficjalnym:",
            "examples": [
                {
                    "en": "Having been approved by the board, the project will begin.",
                    "ua": "Po zatwierdzeniu przez radę projekt ruszy."
                },
                {
                    "en": "Having been elected, she took office immediately.",
                    "ua": "Po wyborze od razu objęła urząd."
                },
                {
                    "en": "Having been tested, the product was released.",
                    "ua": "Po testach produkt wprowadzono na rynek."
                }
            ]
        },
        {
            "label": "Po przyimkach",
            "color": "rose",
            "description": "Może też podkreślać, że coś wydarzyło się wcześniej niż czynność główna:",
            "examples": [
                {
                    "en": "After having been informed, he took action.",
                    "ua": "Po otrzymaniu informacji zaczął działać."
                },
                {
                    "en": "Despite having been warned, she ignored the advice.",
                    "ua": "Mimo ostrzeżenia zignorowała radę."
                },
                {
                    "en": "On having been asked, he explained everything.",
                    "ua": "Zapytany, wszystko wyjaśnił."
                }
            ]
        }
    ]
}

{
    "title": "4. Słowa i wyrażenia z biernym gerundem",
    "sections": [
        {
            "label": "Czasowniki opisujące odczucia",
            "color": "emerald",
            "description": "Po czasownikach takich jak <strong>like, love, hate, enjoy, dislike, prefer, avoid, mind, can't stand</strong>.",
            "examples": [
                {
                    "en": "I can't stand being ignored.",
                    "ua": "Nie znoszę, gdy ktoś mnie ignoruje."
                },
                {
                    "en": "She avoids being seen by him.",
                    "ua": "Unika tego, żeby on ją zobaczył."
                },
                {
                    "en": "They prefer being given clear instructions.",
                    "ua": "Wolą dostawać jasne instrukcje."
                }
            ]
        },
        {
            "label": "Czasowniki pamięci i mówienia",
            "color": "blue",
            "description": "Po czasownikach takich jak <strong>remember, forget, deny, admit, recall, mention</strong>.",
            "examples": [
                {
                    "en": "He admitted being wrong.",
                    "ua": "Przyznał, że się mylił."
                },
                {
                    "en": "She recalls being praised by her teacher.",
                    "ua": "Pamięta, jak nauczycielka ją chwaliła."
                },
                {
                    "en": "He mentioned being offered a job.",
                    "ua": "Wspomniał, że zaoferowano mu pracę."
                }
            ]
        },
        {
            "label": "Wyrażenia stałe",
            "color": "amber",
            "description": "W konstrukcjach takich jak <strong>be worth, be used to, look forward to, be afraid of</strong>.",
            "examples": [
                {
                    "en": "The book is worth being read.",
                    "ua": "Tę książkę warto przeczytać."
                },
                {
                    "en": "She is used to being watched.",
                    "ua": "Jest przyzwyczajona do tego, że ktoś ją obserwuje."
                },
                {
                    "en": "I'm afraid of being punished.",
                    "ua": "Boję się, że zostanę ukarany."
                }
            ]
        }
    ]
}

{
    "title": "5. Porównanie: being done i having been done",
    "intro": "Tak wygląda różnica między prostą formą a biernym gerundem perfect:",
    "rows": [
        {
            "en": "being done",
            "ua": "czynność równoczesna albo ogólna",
            "note": "She hates being interrupted."
        },
        {
            "en": "having been done",
            "ua": "czynność wcześniejsza",
            "note": "After having been warned, he was more careful."
        },
        {
            "en": "being done (after prepositions)",
            "ua": "proces albo współbieżność",
            "note": "He left without being noticed."
        },
        {
            "en": "having been done (cause / sequence)",
            "ua": "wyraźne następstwo albo przyczyna",
            "note": "Having been rejected, she applied again."
        }
    ],
    "warning": "📌 <strong>Having been done</strong> podkreśla, że czynność wydarzyła się <strong>wcześniej</strong> niż czynność główna."
}

{
    "title": "6. Porównanie: Gerund aktywny i pasywny",
    "intro": "Kiedy podmiot wykonuje akcję (aktywną) lub podlega działaniu (bierną):",
    "rows": [
        {
            "en": "Active: He likes helping others.",
            "ua": "Lubi pomagać innym.",
            "note": "On (podmiot) pomaga."
        },
        {
            "en": "Passive: He likes being helped.",
            "ua": "Lubi, gdy mu się pomaga.",
            "note": "On (podmiot) otrzymuje pomoc."
        },
        {
            "en": "Active: I remember telling her.",
            "ua": "Pamiętam, że jej mówiłem.",
            "note": "powiedziałem"
        },
        {
            "en": "Passive: I remember being told.",
            "ua": "Pamiętam, co mi powiedzieli.",
            "note": "Powiedziano mi."
        }
    ],
    "warning": "📌 Jeśli podmiot jest wykonawcą czynności — gerund czynny. Jeśli podmiot podlega działaniu - bierny gerund."
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie elementu <strong>being</strong> w prostej formie biernej.",
            "wrong": "She hates criticized.",
            "right": "✅ She hates being criticized."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie V1 zamiast V3.",
            "wrong": "He enjoys being praise.",
            "right": "✅ He enjoys being praised."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mylenie prostej formy z biernym gerundem perfect.",
            "wrong": "Being warned yesterday, he was careful.",
            "right": "✅ Having been warned yesterday, he was careful."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Zły szyk w formie perfect.",
            "wrong": "been having done",
            "right": "✅ having been done"
        }
    ]
}
